begin;

alter table public.level_xp_thresholds add column requirement integer;
update public.level_xp_thresholds t set requirement=n.total_xp-t.total_xp from public.level_xp_thresholds n where n.level=t.level+1;
alter table public.level_xp_thresholds add constraint level_xp_thresholds_requirement_check check(requirement is null or requirement>0);

create type public.action_tier as enum ('common','rare','epic','legendary');
create type public.action_submission_status as enum ('pending','accepted','rejected','expired','cancelled');
create type public.action_cancellation_reason as enum ('owner_hospitalized','run_ended','admin_cancelled');

create table public.action_definitions(
 id text primary key check(id=lower(id) and id~'^[a-z0-9_]+$'), name text not null, short_description text not null,
 category text not null, tier public.action_tier not null, xp_basis_points integer not null check(xp_basis_points>0),
 coin_reward integer not null check(coin_reward>=0), hp_cost integer not null check(hp_cost>=0), cooldown_seconds integer check(cooldown_seconds>0),
 daily_cap integer check(daily_cap>0), festival_cap integer check(festival_cap>0), distinct_reference_kind text check(distinct_reference_kind in('person','group','item')),
 is_enabled boolean not null, is_extreme_challenge boolean not null default false, challenge_text text,
 image_key text not null, hourglass_resettable boolean not null default false,
 check(not is_extreme_challenge or (id='extreme_challenge' and daily_cap=1))
);
create index action_definitions_enabled_tier_idx on public.action_definitions(is_enabled,tier);

create table public.action_submissions(
 id uuid primary key default gen_random_uuid(), game_run_id uuid not null references public.game_runs(id), owner_player_id uuid not null references public.players(id),
 action_id text not null references public.action_definitions(id), status public.action_submission_status not null default 'pending',
 submitted_at timestamptz not null default clock_timestamp(), expires_at timestamptz not null,
 validator_player_id uuid references public.players(id), accepted_at timestamptz, rejected_at timestamptz, resolved_at timestamptz,
 cancellation_reason public.action_cancellation_reason, created_by_idempotency_key uuid not null,
 check(expires_at>submitted_at), check(owner_player_id is distinct from validator_player_id),
 check((status='pending' and validator_player_id is null and resolved_at is null and cancellation_reason is null) or
       (status='accepted' and validator_player_id is not null and accepted_at is not null and resolved_at=accepted_at and cancellation_reason is null) or
       (status='rejected' and validator_player_id is not null and rejected_at is not null and resolved_at=rejected_at and cancellation_reason is null) or
       (status='expired' and validator_player_id is null and resolved_at is not null and cancellation_reason is null) or
       (status='cancelled' and resolved_at is not null and cancellation_reason is not null))
);
create unique index action_submissions_pending_action_idx on public.action_submissions(game_run_id,owner_player_id,action_id) where status='pending';
create unique index action_submissions_submit_key_idx on public.action_submissions(game_run_id,owner_player_id,created_by_idempotency_key);
create index action_submissions_pool_idx on public.action_submissions(game_run_id,status,submitted_at) where status='pending';
create index action_submissions_owner_pending_idx on public.action_submissions(game_run_id,owner_player_id) where status='pending';
create index action_submissions_expiry_idx on public.action_submissions(expires_at) where status='pending';

create table public.action_usages(
 id uuid primary key default gen_random_uuid(),game_run_id uuid not null,player_id uuid not null,action_id text not null references public.action_definitions(id),
 submission_id uuid not null unique references public.action_submissions(id),accepted_at timestamptz not null,festival_day_key date not null,
 foreign key(game_run_id,player_id) references public.player_run_states(game_run_id,player_id)
);
create index action_usages_daily_idx on public.action_usages(game_run_id,player_id,action_id,festival_day_key);
create index action_usages_festival_idx on public.action_usages(game_run_id,player_id,action_id);
create table public.action_cooldowns(game_run_id uuid not null,player_id uuid not null,action_id text not null references public.action_definitions(id),cooldown_ends_at timestamptz not null,source_submission_id uuid not null references public.action_submissions(id),updated_at timestamptz not null default clock_timestamp(),primary key(game_run_id,player_id,action_id),foreign key(game_run_id,player_id) references public.player_run_states(game_run_id,player_id));
create index action_cooldowns_due_idx on public.action_cooldowns(game_run_id,player_id,cooldown_ends_at);
create table public.daily_quest_progress(game_run_id uuid not null,player_id uuid not null,festival_day_key date not null,accepted_actions integer not null default 0 check(accepted_actions>=0),successful_validations integer not null default 0 check(successful_validations>=0),created_at timestamptz not null default clock_timestamp(),updated_at timestamptz not null default clock_timestamp(),primary key(game_run_id,player_id,festival_day_key),foreign key(game_run_id,player_id) references public.player_run_states(game_run_id,player_id));
create index daily_quest_progress_lookup_idx on public.daily_quest_progress(game_run_id,player_id,festival_day_key);
create table public.daily_quest_distinct_actions(game_run_id uuid not null,player_id uuid not null,festival_day_key date not null,action_id text not null references public.action_definitions(id),created_at timestamptz not null default clock_timestamp(),primary key(game_run_id,player_id,festival_day_key,action_id),foreign key(game_run_id,player_id,festival_day_key) references public.daily_quest_progress(game_run_id,player_id,festival_day_key));
create table public.daily_quest_completions(id uuid primary key default gen_random_uuid(),game_run_id uuid not null,player_id uuid not null,festival_day_key date not null,quest_id text not null check(quest_id in('easy_accepted_5','easy_validations_10','easy_variety_5','medium_accepted_10','medium_validations_15','hard_daily_mastery')),xp_granted integer not null,coins_granted integer not null,completed_at timestamptz not null default clock_timestamp(),unique(game_run_id,player_id,festival_day_key,quest_id),foreign key(game_run_id,player_id,festival_day_key) references public.daily_quest_progress(game_run_id,player_id,festival_day_key));
create table public.hospital_stays(id uuid primary key default gen_random_uuid(),game_run_id uuid not null,player_id uuid not null,source_submission_id uuid references public.action_submissions(id),started_at timestamptz not null, hospital_until timestamptz not null,released_at timestamptz,xp_lost integer not null check(xp_lost>=0),foreign key(game_run_id,player_id) references public.player_run_states(game_run_id,player_id),check(hospital_until>started_at));
create unique index hospital_stays_active_idx on public.hospital_stays(game_run_id,player_id) where released_at is null;

